import { formatSeriesNameForDisplay } from './format-series-name-for-display.js';
import type { SeriesName } from '../../../types.js';

export const getDisplayNameText = (
  name: SeriesName,
  multiLine: boolean,
): SeriesName => {
  if (Array.isArray(name)) {
    return multiLine ? name : formatSeriesNameForDisplay(name);
  }
  return name || '';
};
